using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e6 + 5;
int n, m;
int a[MAXN], cnt = 0, d = 1;
vector<int> ve[MAXN];
void bfs(int x)
{
	ve[d].push_back(x);
}
void dfs(int l, int r, int sum)
{
	//cout<<l<<' '<<r<<' '<<sum<<'\n';
	if (sum > m)return;
	if (l > r)
	{
		bfs(sum);
		return   ;
	}
	dfs(l + 1, r, sum + a[l]);
	dfs(l + 1, r, sum);
}
